package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVParser;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedConstruction;
import org.mockito.Mockito;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testParseReturnsCSVParserInstance() throws IOException {
        Reader mockReader = mock(Reader.class);
        try (MockedConstruction<CSVParser> mocked = Mockito.mockConstruction(CSVParser.class,
                (mock, context) -> {
                    // no-op
                })) {

            CSVParser parser = csvFormat.parse(mockReader);

            assertNotNull(parser, "parse should return a non-null CSVParser instance");
            assertEquals(mocked.constructed().get(0), parser, "parse should return the CSVParser constructed");
        }
    }

    @Test
    public void testParseThrowsIOException() throws IOException {
        Reader mockReader = mock(Reader.class);

        try (MockedConstruction<CSVParser> mocked = Mockito.mockConstruction(CSVParser.class,
                (mock, context) -> {
                    doThrow(new IOException("IO error")).when(mock).close();
                })) {

            // Because parse just constructs CSVParser and returns it, it does not throw IOException itself.
            // So to test IOException thrown, we simulate the constructor throwing IOException.

            IOException ioException = assertThrows(IOException.class, () -> {
                try (MockedConstruction<CSVParser> mocked2 = Mockito.mockConstruction(CSVParser.class,
                        (mock, context) -> {
                            throw new IOException("Simulated IO exception");
                        })) {
                    csvFormat.parse(mockReader);
                }
            });
            assertEquals("Simulated IO exception", ioException.getMessage());
        }
    }

    @Test
    public void testParseWithNullReaderThrowsNullPointerException() {
        assertThrows(NullPointerException.class, () -> csvFormat.parse(null));
    }
}
